import org.junit.jupiter.api.Test;

class CascadesIncompleteJoinWorkLifecycleTest {

	@Test
	void duplicateRawJoinPartitionsAreChargedBeforeMemoDeduplication() {
		AtomicInteger callbacks = new AtomicInteger();
		JoinSearchContributor duplicatePartitions = new JoinSearchContributor() {
			private final Descriptor descriptor = new Descriptor("duplicate-partitions", Coverage.EXHAUSTIVE_LEGAL,
					100);

			@Override
			public Descriptor descriptor() {
				return descriptor;
			}

			@Override
			public Outcome contribute(JoinSearchRequest request, CandidateSink sink) {
				throw new AssertionError("production Cascades search must request memo-local expressions");
			}

			@Override
			public Outcome contributeMemoExpressions(JoinSearchRequest request, MemoExpressionSink sink) {
				JoinMemoExpression expression = JoinMemoExpression.decompose(reversedTwoFactorTree(request)).getFirst();
				callbacks.incrementAndGet();
				sink.accept(expression);
				callbacks.incrementAndGet();
				sink.accept(expression);
				return Outcome.completed();
			}
		};

		CascadesPlan plan = planner(List.of(duplicatePartitions)).optimize(twoFactorJoin(), OptimizationGoal.root());

		assertEquals(2, callbacks.get());
		assertEquals(2L, plan.searchStatus().counters().partitionProbes(),
				"Every raw partition callback must be charged even when memo deduplication rejects it");
	}

	@Test
	void exactModeResumesPartiallyEnumeratedJoinWorkUntilComplete() {
		AtomicReference<JoinSearchDependencyStamp> incompleteRevision = new AtomicReference<>();
		AtomicInteger incompleteRevisionCalls = new AtomicInteger();
		ExhaustiveLegalJoinSearchContributor completion = new ExhaustiveLegalJoinSearchContributor();
		JoinSearchContributor resumable = new JoinSearchContributor() {
			private final Descriptor descriptor = new Descriptor("resumable-exhaustive", Coverage.EXHAUSTIVE_LEGAL,
					100);

			@Override
			public Descriptor descriptor() {
				return descriptor;
			}

			@Override
			public Outcome contribute(JoinSearchRequest request, CandidateSink sink) {
				incompleteRevision.compareAndSet(null, request.dependencyStamp());
				if (request.dependencyStamp().equals(incompleteRevision.get())
						&& incompleteRevisionCalls.incrementAndGet() == 1) {
					sink.accept(reversedTwoFactorTree(request));
					return Outcome.budgetExhausted("resume after the partial candidate");
				}
				return completion.contribute(request, sink);
			}
		};

		CascadesPlan plan = planner(List.of(resumable)).optimize(twoFactorJoin(), OptimizationGoal.root());

		assertEquals(2, incompleteRevisionCalls.get(),
				"Exact mode must resume the same incomplete region revision exactly once");
		assertEquals(3L, plan.searchStatus().counters().partitionProbes(),
				"One partial callback and both oriented exhaustive callbacks must share the retry ledger");
		assertEquals(OptimizationCompleteness.COMPLETE, plan.completeness(), plan.diagnostics().toString());
		assertNoPendingJoinWork(plan);
	}

	@Test
	void completedRetryClearsPreviouslyUnsupportedJoinWork() {
		AtomicReference<JoinSearchDependencyStamp> unsupportedRevision = new AtomicReference<>();
		AtomicInteger unsupportedRevisionCalls = new AtomicInteger();
		ExhaustiveLegalJoinSearchContributor completion = new ExhaustiveLegalJoinSearchContributor();
		JoinSearchContributor initiallyUnsupported = new JoinSearchContributor() {
			private final Descriptor descriptor = new Descriptor("eventually-supported-exhaustive",
					Coverage.EXHAUSTIVE_LEGAL, 100);

			@Override
			public Descriptor descriptor() {
				return descriptor;
			}

			@Override
			public Outcome contribute(JoinSearchRequest request, CandidateSink sink) {
				unsupportedRevision.compareAndSet(null, request.dependencyStamp());
				if (request.dependencyStamp().equals(unsupportedRevision.get())
						&& unsupportedRevisionCalls.incrementAndGet() == 1) {
					return Outcome.unsupported("waiting for another contributor to add a memo alternative");
				}
				return completion.contribute(request, sink);
			}
		};
		JoinSearchContributor openingRewrite = new JoinSearchContributor() {
			private final Descriptor descriptor = new Descriptor("opening-join-rewrite", Coverage.HEURISTIC, 200);

			@Override
			public Descriptor descriptor() {
				return descriptor;
			}

			@Override
			public Outcome contribute(JoinSearchRequest request, CandidateSink sink) {
				sink.accept(reversedTwoFactorTree(request));
				return Outcome.completed();
			}
		};

		CascadesPlan plan = planner(List.of(initiallyUnsupported, openingRewrite))
				.optimize(twoFactorJoin(), OptimizationGoal.root());

		assertEquals(2, unsupportedRevisionCalls.get(),
				"The memo change must wake the same previously unsupported region revision exactly once");
		assertEquals(OptimizationCompleteness.COMPLETE, plan.completeness(), plan.diagnostics().toString());
		assertNoPendingJoinWork(plan);
	}

	private static CascadesPlanner planner(List<? extends JoinSearchContributor> contributors) {
		return new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()),
				RuleRegistry.builder().add(new StandardCascadesRules.GenericImplementationRule()).build(),
				CascadesTelemetry.NO_OP, 16, RewriteMetadata.empty(),
				new JoinSearchService(contributors));
	}

	private static JoinTree reversedTwoFactorTree(JoinSearchRequest request) {
		List<Integer> occurrences = request.region()
				.factors()
				.stream()
				.map(factor -> factor.occurrenceId())
				.toList();
		assertEquals(2, occurrences.size());
		return JoinTree.join(JoinTree.factor(occurrences.get(1)), JoinTree.factor(occurrences.get(0)));
	}

	private static void assertNoPendingJoinWork(CascadesPlan plan) {
		assertFalse(plan.pendingTasks()
				.stream()
				.anyMatch(task -> task.kind() == PendingOptimizationTask.Kind.ENUMERATE_JOIN),
				"Completed join work must remove stale pending entries: " + plan.pendingTasks());
	}

	private static Join twoFactorJoin() {
		return new Join(pattern("a", "p1", "b"), pattern("b", "p2", "c"));
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject), new Var(predicate), new Var(object));
	}
}
